import React from "react";
import { positions } from "../data/data";

const Positions = () => {
  // Safe validation check: if data array itself is missing/broken, display zero state cleanly
  const safePositions = Array.isArray(positions) ? positions : [];

  return (
    <div className="positions-container">
      <div className="positions-header">
        <h6>Positions ({safePositions.length})</h6>
        <hr className="divider" />
      </div>

      <div className="table-container">
        <table className="positions-table">
          <thead>
            <tr>
              <th>Product</th>
              <th>Instrument</th>
              <th>Qty.</th>
              <th>Avg. cost</th>
              <th>LTP</th>
              <th>P&L</th>
              <th>Day chg.</th>
            </tr>
          </thead>
          <tbody>
            {safePositions.map((stock, index) => {
              // Defensive fallbacks to prevent undefined crashes
              const qty = Number(stock?.qty) || 0;
              const avg = Number(stock?.avg) || 0;
              const price = Number(stock?.price) || 0;
              const productName = stock?.product || "N/A";
              const instrumentName = stock?.name || "Unknown";
              const dayChange = stock?.day || "0.00%";

              // Calculation logic using verified numbers
              const curValue = price * qty;
              const totalCost = avg * qty;
              const pnl = curValue - totalCost;

              const isProfit = pnl >= 0;
              const isDayProfit = !stock?.isLoss;

              return (
                <tr key={index}>
                  <td>
                    <span className="product-type">{productName}</span>
                  </td>
                  <td className="instrument-name">{instrumentName}</td>
                  <td>{qty}</td>
                  <td>{avg.toFixed(2)}</td>
                  <td>{price.toFixed(2)}</td>
                  <td className={isProfit ? "profit-text" : "loss-text"}>
                    {pnl.toFixed(2)}
                  </td>
                  <td className={isDayProfit ? "profit-text" : "loss-text"}>
                    {dayChange}
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default Positions;
